import React from 'react';
import '..style/FilterOption.css';

const FilterOption = ({ text, onClick, isSelected }) => {
    return (
        <div
            className={`filter-option ${isSelected ? 'selected' : ''}`}
            onClick={() => onClick(text)}
        >
            {text}
        </div>
    );
};

export default FilterOption;
